---
import ArrowLeftIcon from "lucide-static/icons/arrow-left.svg"
import ArrowRightIcon from "lucide-static/icons/arrow-right.svg"
import CheckIcon from "lucide-static/icons/check.svg"
import ChevronDownIcon from "lucide-static/icons/chevron-down.svg"
import CopyIcon from "lucide-static/icons/copy.svg"
import ExternalLinkIcon from "lucide-static/icons/external-link.svg"
import ClaudeIcon from "simple-icons/icons/claude.svg"
import CursorIcon from "simple-icons/icons/cursor.svg"
import MarkdownIcon from "simple-icons/icons/markdown.svg"

import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import { buttonVariants } from "@/components/ui/button/button-variants"
import {
  Card,
  CardDescription,
  CardFooter,
  CardHeader,
} from "@/components/ui/card"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import { SectionContainer } from "@/components/ui/section"
import {
  Toc,
  TocMenu,
  TocMenuItem,
  TocMenuLink,
  TocTitle,
} from "@/components/ui/toc"
import {
  Typography,
  TypographyH1,
  TypographyLead,
} from "@/components/ui/typography"

type Props = {
  class?: string
  title: string
  description?: string
  copyButton?: {
    id: string
    source: string
  }
  markdownUrl?: string
  tocItems: {
    depth: number
    href: string
    label: string
  }[]
  callout?: {
    description: string
    button: {
      label: string
      href: string
      variant?: "default" | "outline" | "secondary" | "ghost"
    }
  }
  previousPage?: {
    href: string
    title: string
  }
  nextPage?: {
    href: string
    title: string
  }
  labels: {
    copyMarkdown: string
    openIn: string
    openInMarkdown: string
    openInChatGPT: string
    openInClaude: string
    openInCursor: string
    pagination: {
      previous: string
      next: string
      ariaLabel: string
    }
    toc: string
  }
}

const {
  class: className,
  title,
  description,
  copyButton,
  markdownUrl,
  tocItems,
  callout,
  previousPage,
  nextPage,
  labels,
} = Astro.props
const showCopyButton = Boolean(copyButton)
const showOpenButton = Boolean(markdownUrl)
const showPagination = Boolean(previousPage || nextPage)
const assistantPrompt = markdownUrl
  ? `Read ${markdownUrl}, I want to ask questions about it.`
  : ""
const openLinks = markdownUrl
  ? [
      {
        label: labels.openInMarkdown,
        href: markdownUrl,
        icon: "markdown",
      },
      {
        label: labels.openInChatGPT,
        href: `https://chatgpt.com/?hints=search&q=${encodeURIComponent(assistantPrompt)}`,
        icon: "chatgpt",
      },
      {
        label: labels.openInClaude,
        href: `https://claude.ai/new?q=${encodeURIComponent(assistantPrompt)}`,
        icon: "claude",
      },
      {
        label: labels.openInCursor,
        href: `https://cursor.com/link/prompt?text=${encodeURIComponent(assistantPrompt)}`,
        icon: "cursor",
      },
    ]
  : []
---

<SectionContainer
  class={cn(
    "gap-10 pt-10 pb-8 sm:pt-12 sm:pb-10 xl:grid xl:grid-cols-[minmax(0,1fr)_16rem] xl:items-start xl:gap-x-16",
    className
  )}
>
  <div class="mx-auto flex w-full max-w-3xl min-w-0 flex-col gap-10">
    <header
      class="flex flex-col gap-4 sm:flex-row sm:items-start sm:justify-between"
    >
      <div class="flex min-w-0 flex-1 flex-col gap-2">
        <TypographyH1
          size="sm"
          class="text-foreground text-left tracking-tight"
        >
          {title}
        </TypographyH1>
        {
          description && (
            <TypographyLead class="max-w-2xl text-base! leading-7">
              {description}
            </TypographyLead>
          )
        }
      </div>
      <div class="flex shrink-0 items-center gap-2 self-start">
        {
          showCopyButton && (
            <Button
              id={copyButton?.id}
              type="button"
              variant="outline"
              size="xs"
              data-source={copyButton?.source}
              aria-label={labels.copyMarkdown}
            >
              <CopyIcon data-copy-icon class="docs-copy-icon size-3.5" />
              <CheckIcon
                data-check-icon
                class="docs-check-icon hidden size-3.5"
              />
              <span>{labels.copyMarkdown}</span>
            </Button>
          )
        }
        {
          showOpenButton && (
            <DropdownMenu>
              <DropdownMenuTrigger
                class={buttonVariants({ variant: "outline", size: "xs" })}
              >
                <span>{labels.openIn}</span>
                <ChevronDownIcon class="size-3.5 opacity-70" />
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end" sideOffset={6} class="w-56">
                {openLinks.map((link) => (
                  <a
                    href={link.href}
                    target="_blank"
                    rel="noreferrer noopener"
                    class="hover:bg-accent hover:text-accent-foreground flex items-center gap-2 rounded-sm px-2 py-1.5 text-sm transition-colors outline-none"
                  >
                    {link.icon === "markdown" && (
                      <MarkdownIcon class="size-4 fill-current" />
                    )}
                    {link.icon === "chatgpt" && (
                      <svg
                        role="img"
                        viewBox="0 0 24 24"
                        fill="currentColor"
                        class="size-4"
                        aria-hidden="true"
                      >
                        <path d="M22.282 9.821a5.985 5.985 0 0 0-.516-4.91 6.046 6.046 0 0 0-6.51-2.9A6.065 6.065 0 0 0 4.981 4.182a5.985 5.985 0 0 0-3.998 2.9 6.046 6.046 0 0 0 .743 7.097 5.98 5.98 0 0 0 .511 4.91 6.051 6.051 0 0 0 6.515 2.9A5.985 5.985 0 0 0 13.26 24a6.056 6.056 0 0 0 5.772-4.206 5.989 5.989 0 0 0 3.998-2.9 6.056 6.056 0 0 0-.748-7.073ZM13.26 22.43a4.476 4.476 0 0 1-2.876-1.04l.142-.081 4.778-2.758a.795.795 0 0 0 .393-.681v-6.737l2.02 1.169a.071.071 0 0 1 .038.052v5.583a4.504 4.504 0 0 1-4.495 4.494Zm-9.66-4.125a4.471 4.471 0 0 1-.535-3.014l.142.085 4.783 2.758a.771.771 0 0 0 .781 0l5.843-3.368v2.332a.08.08 0 0 1-.034.062L9.74 19.95a4.499 4.499 0 0 1-6.14-1.646ZM2.34 7.896a4.485 4.485 0 0 1 2.366-1.973V11.6a.766.766 0 0 0 .388.677l5.814 3.354-2.02 1.169a.076.076 0 0 1-.071 0l-4.83-2.787A4.504 4.504 0 0 1 2.34 7.872Zm16.596 3.856-5.833-3.388L15.12 7.2a.076.076 0 0 1 .071 0l4.83 2.791a4.494 4.494 0 0 1-.676 8.104v-5.677a.79.79 0 0 0-.407-.667Zm2.011-3.024-.142-.085-4.774-2.782a.776.776 0 0 0-.785 0L9.409 9.23V6.897a.066.066 0 0 1 .028-.061l4.83-2.787a4.499 4.499 0 0 1 6.68 4.66ZM8.307 12.863l-2.02-1.164a.08.08 0 0 1-.038-.057V6.074a4.499 4.499 0 0 1 7.376-3.453l-.142.08-4.778 2.758a.795.795 0 0 0-.393.681Zm1.097-2.365 2.602-1.5 2.607 1.5v2.999l-2.597 1.5-2.607-1.5Z" />
                      </svg>
                    )}
                    {link.icon === "claude" && (
                      <ClaudeIcon class="size-4 fill-current" />
                    )}
                    {link.icon === "cursor" && (
                      <CursorIcon class="size-4 fill-current" />
                    )}
                    <span>{link.label}</span>
                    <ExternalLinkIcon class="text-muted-foreground ml-auto size-3.5" />
                  </a>
                ))}
              </DropdownMenuContent>
            </DropdownMenu>
          )
        }
      </div>
    </header>

    <Typography as="article" size="sm">
      <slot />
    </Typography>

    {
      showPagination && (
        <nav
          class="flex items-center justify-between gap-3"
          aria-label={labels.pagination.ariaLabel}
        >
          {previousPage ? (
            <Button
              as="a"
              href={previousPage.href}
              variant="outline"
              class="h-auto min-w-0 items-center justify-start gap-2 px-3 py-2 whitespace-normal"
            >
              <ArrowLeftIcon class="size-4" />
              <span class="truncate text-sm font-medium">
                {previousPage.title}
              </span>
            </Button>
          ) : (
            <div aria-hidden="true" />
          )}

          {nextPage ? (
            <Button
              as="a"
              href={nextPage.href}
              variant="outline"
              class="h-auto min-w-0 items-center justify-end gap-2 px-3 py-2 text-right whitespace-normal"
            >
              <span class="truncate text-sm font-medium">{nextPage.title}</span>
              <ArrowRightIcon class="size-4" />
            </Button>
          ) : (
            <div aria-hidden="true" />
          )}
        </nav>
      )
    }
  </div>

  {
    (tocItems.length > 0 || callout) && (
      <aside class="hidden w-64 xl:sticky xl:top-12 xl:mr-0 xl:ml-auto xl:block xl:self-start">
        <div class="flex flex-col gap-6">
          {tocItems.length > 0 && (
            <Toc aria-label={labels.toc}>
              <TocTitle>{labels.toc}</TocTitle>
              <TocMenu>
                {tocItems.map((item) => (
                  <TocMenuItem>
                    <TocMenuLink href={item.href} depth={item.depth}>
                      {item.label}
                    </TocMenuLink>
                  </TocMenuItem>
                ))}
              </TocMenu>
            </Toc>
          )}

          {callout && (
            <Card size="sm">
              <CardHeader>
                <CardDescription>{callout.description}</CardDescription>
              </CardHeader>
              <CardFooter>
                <Button
                  as="a"
                  href={callout.button.href}
                  variant={callout.button.variant}
                  size="sm"
                  target="_blank"
                  rel="noreferrer"
                >
                  {callout.button.label}
                </Button>
              </CardFooter>
            </Card>
          )}
        </div>
      </aside>
    )
  }
</SectionContainer>

<script is:inline>
  const copyIcon = `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect width="14" height="14" x="8" y="8" rx="2" ry="2"></rect><path d="M4 16c-1.1 0-2-.9-2-2V4c0-1.1.9-2 2-2h10c1.1 0 2 .9 2 2"></path></svg>`
  const checkIcon = `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M20 6 9 17l-5-5"></path></svg>`
  document.querySelectorAll("[data-slot='typography'] > pre").forEach((pre) => {
    if (pre.closest(".docs-code-block")) return
    const wrapper = document.createElement("div")
    const button = document.createElement("button")
    wrapper.className = "docs-code-block"
    button.type = "button"
    button.className = "docs-code-copy"
    button.ariaLabel = "Copy code"
    button.innerHTML = `<span data-copy-icon>${copyIcon}</span><span data-check-icon class="hidden">${checkIcon}</span>`
    pre.before(wrapper)
    wrapper.append(pre, button)
  })

  const writeToClipboard = async (text) => {
    if (navigator.clipboard && window.isSecureContext) {
      try {
        await navigator.clipboard.writeText(text)
        return true
      } catch {
        // Fall through to the textarea copy path.
      }
    }

    const textarea = document.createElement("textarea")
    textarea.value = text
    textarea.setAttribute("readonly", "")
    textarea.style.position = "fixed"
    textarea.style.inset = "0 auto auto 0"
    textarea.style.opacity = "0"
    document.body.append(textarea)
    textarea.select()
    textarea.setSelectionRange(0, text.length)

    try {
      return document.execCommand("copy")
    } finally {
      textarea.remove()
    }
  }

  const showCopySuccess = (button) => {
    button.querySelector("[data-copy-icon]")?.classList.add("hidden")
    button.querySelector("[data-check-icon]")?.classList.remove("hidden")
    setTimeout(() => {
      button.querySelector("[data-copy-icon]")?.classList.remove("hidden")
      button.querySelector("[data-check-icon]")?.classList.add("hidden")
    }, 1200)
  }

  document.addEventListener("click", async (event) => {
    const button = event.target?.closest?.(
      "[id^='docs-copy-page-'], .docs-code-copy"
    )
    if (!button) return
    const source =
      button.dataset.source ??
      button
        .closest(".docs-code-block")
        ?.querySelector("pre")
        ?.textContent?.replace(/\n$/, "")
    if (!source) return

    const copied = await writeToClipboard(source)
    if (copied) showCopySuccess(button)
  })
</script>
